// HairStoryPresetsGenerator_FIX.cs - Исправления для Story пресетов\n// Добавляет правильное распределение по зонам для Diana, Grace и Desmond\n#if UNITY_EDITOR\nusing UnityEditor;\nusing UnityEngine;\nusing CharacterEditor.Hair;\nusing CharacterEditor.Hair.Proc;\n\nnamespace CharacterEditor.Hair.EditorTool\n{\n    /// <summary>\n    /// Дополнительный фикс для пресетов, сгенерированных HairStoryPresetsGenerator.\n    /// Исправляет Diana (рандомные корни → зоны), Grace (правильная зона для хвоста) и Desmond (bundle anchor).\n    /// Запускать ПОСЛЕ генерации.\n    /// </summary>\n    public static class HairStoryPresetsFix\n    {\n        [MenuItem(\"Tools/Character/Hair/Fix Story Presets - Diana/Grace/Desmond\", false, 34)]\n        public static void FixStoryPresets()\n        {\n            ScalpProfileDefinition profile = FindFirst<ScalpProfileDefinition>();\n            if (profile == null)\n            {\n                EditorUtility.DisplayDialog(\"Fix Story\", \"No ScalpProfile found. Run Setup Wizard first.\", \"OK\");\n                return;\n            }\n\n            // === Diana ===\n            var diana = FindPiece(\"diana\");\n            if (diana != null)\n            {\n                Undo.RecordObject(diana, \"Fix Diana roots\");\n                diana.scalpProfile = profile;\n                FixDianaRoots(diana, profile);\n                EditorUtility.SetDirty(diana);\n                Debug.Log(\"[StoryFix] Fixed Diana: distributed roots to scalp zones.\", diana);\n            }\n\n            // === Grace ===\n            var grace = FindPiece(\"grace\");\n            if (grace != null)\n            {\n                Undo.RecordObject(grace, \"Fix Grace roots\");\n                grace.scalpProfile = profile;\n                // Grace's hair should use SideLeft/SideRight zones correctly\n                // The current preset has groupId 1=left, 2=right - this maps to SideLeft/SideRight zones\n                EditorUtility.SetDirty(grace);\n                Debug.Log(\"[StoryFix] Grace: scalpProfile assigned.\", grace);\n            }\n\n            // === Desmond ===\n            var desmond = FindPiece(\"desmond\");\n            if (desmond != null)\n            {\n                Undo.RecordObject(desmond, \"Fix Desmond bundle anchor\");\n                desmond.scalpProfile = profile;\n                // Добавляем BundleAnchor для пучка\n                desmond.bundleAnchors = new BundleAnchor[]\n                {\n                    new BundleAnchor\n                    {\n                        id = \"ponytail_low\",\n                        attachBone = \"c_head\",\n                        localOffset = new Vector3(0, -0.08f, -0.09f),\n                        gatherRadius = 0.022f,\n                        pinT = 0.28f,\n                        tailSlack = 0.7f\n                    }\n                };\n                EditorUtility.SetDirty(desmond);\n                Debug.Log(\"[StoryFix] Desmond: added bundle anchor for ponytail.\", desmond);\n            }\n\n            // === Wenona ===\n            var wenona = FindPiece(\"wenona\");\n            if (wenona != null)\n            {\n                Undo.RecordObject(wenona, \"Fix Wenona braid\");\n                // Убеждаемся что braid настроен\n                if (wenona.defaultBraid.type == BraidType.None)\n                {\n                    wenona.defaultBraid = new BraidProfile\n                    {\n                        type = BraidType.ThreeStrand,\n                        crossings = 9,\n                        strandRadius = 0.011f,\n                        tightness = 0.9f,\n                        taperEnd = true\n                    };\n                }\n                EditorUtility.SetDirty(wenona);\n                Debug.Log(\"[StoryFix] Wenona: ensured braid settings.\", wenona);\n            }\n\n            AssetDatabase.SaveAssets();\n\n            EditorUtility.DisplayDialog(\"Story Fix Complete\",\n                \"Fixed: Diana, Grace, Desmond, Wenona.\\n\\n\" +\n                \"Now run 'Fix ALL Hair Roots To Scalp Zones' and 'Rebuild Hair Catalog'.\",\n                \"OK\");\n        }\n\n        private static void FixDianaRoots(HairPieceDefinitionProc piece, ScalpProfileDefinition profile)\n        {\n            var guides = piece.guides;\n            if (guides == null || guides.Length == 0) return;\n\n            var rnd = new System.Random(7717);\n            for (int i = 0; i < guides.Length; i++)\n            {\n                var g = guides[i];\n                // Определяем зону по groupId\n                ScalpZoneId zone;\n                switch (g.groupId)\n                {\n                    case 1: zone = ScalpZoneId.SideLeftTop; break;\n                    case 2: zone = ScalpZoneId.SideRightTop; break;\n                    default: zone = ScalpZoneId.BangsFront; break;\n                }\n\n                float u = (float)(rnd.NextDouble() * 2f - 1f);\n                float v = (float)(rnd.NextDouble() * 2f - 1f);\n                Vector3 newRoot = profile.GetRoot(zone, u, v);\n                g.rootLocalPos = newRoot;\n                guides[i] = g;\n            }\n            piece.guides = guides;\n        }\n\n        private static HairPieceDefinitionProc FindPiece(string namePart)\n        {\n            string[] guids = AssetDatabase.FindAssets(\"t:HairPieceDefinitionProc \" + namePart);\n            foreach (string guid in guids)\n            {\n                string path = AssetDatabase.GUIDToAssetPath(guid);\n                var p = AssetDatabase.LoadAssetAtPath<HairPieceDefinitionProc>(path);\n                if (p != null && (p.id ?? \"\").ToLowerInvariant().Contains(namePart))\n                    return p;\n            }\n            // Fallback: ищем по всем\n            guids = AssetDatabase.FindAssets(\"t:HairPieceDefinitionProc\");\n            foreach (string guid in guids)\n            {\n                string path = AssetDatabase.GUIDToAssetPath(guid);\n                var p = AssetDatabase.LoadAssetAtPath<HairPieceDefinitionProc>(path);\n                if (p != null && ((p.id ?? \"\") + (p.name ?? \"\")).ToLowerInvariant().Contains(namePart))\n                    return p;\n            }\n            return null;\n        }\n\n        private static T FindFirst<T>() where T : ScriptableObject\n        {\n            string[] guids = AssetDatabase.FindAssets(\"t:\" + typeof(T).Name);\n            if (guids.Length == 0) return null;\n            return AssetDatabase.LoadAssetAtPath<T>(AssetDatabase.GUIDToAssetPath(guids[0]));\n        }\n    }\n}\n#endif\n"}